  1→// ABOUTME: Dashboard client — fetches session data, renders UI, handles interactions.
  2→// ABOUTME: Vanilla JS with no build step; polls /api/sessions for updates.
  3→
  4→(function () {
  5→  "use strict";
  6→
  7→  // --- State ---
  8→  let dashboardData = null;
  9→  let lastScannedTime = null;
 10→  let expandedRepos = new Set(); // repo_root values that are expanded
 11→  var timeFilterDays = Infinity; // max days back to show (Infinity = all)
 12→
 13→  // --- DOM refs ---
 14→  const $loading = document.getElementById("loading");
 15→  const $repoGroups = document.getElementById("repo-groups");
 16→  const $nonRepoGroups = document.getElementById("non-repo-groups");
 17→  const $chronoView = document.getElementById("chrono-view");
 18→  const $emptyState = document.getElementById("empty-state");
 19→  const $lastScan = document.getElementById("last-scan");
 20→  const $btnRefresh = document.getElementById("btn-refresh");
 21→  const $scanDays = document.getElementById("scan-days");
 22→  const $timeSlider = document.getElementById("time-slider");
 23→  const $timeSliderLabel = document.getElementById("time-slider-label");
 24→  const $searchOverlay = document.getElementById("search-overlay");
 25→  const $searchInput = document.getElementById("search-input");
 26→  const $searchResults = document.getElementById("search-results");
 27→
 28→  // --- Helpers ---
 29→
 30→  function timeAgo(isoString) {
 31→    if (!isoString) return "--";
 32→    const diff = Date.now() - new Date(isoString).getTime();
 33→    const seconds = Math.floor(diff / 1000);
 34→    if (seconds < 60) return seconds + "s ago";
 35→    const minutes = Math.floor(seconds / 60);
 36→    if (minutes < 60) return minutes + "m ago";
 37→    const hours = Math.floor(minutes / 60);
 38→    if (hours < 24) return hours + "h ago";
 39→    const days = Math.floor(hours / 24);
 40→    return days + "d ago";
 41→  }
 42→
 43→  function statusCssClass(status) {
 44→    return (status || "").replace(/\s+/g, "-");
 45→  }
 46→
 47→  function isActiveDot(status) {
 48→    return ["in progress", "likely in progress", "waiting for input"].includes(status);
 49→  }
 50→
 51→  var INITIAL_VISIBLE = 10;
 52→
 53→  function escapeHtml(str) {
 54→    const div = document.createElement("div");
 55→    div.textContent = str || "";
 56→    return div.innerHTML;
 57→  }
 58→
 59→  function sessionLabel(session) {
 60→    if (session.summary) return session.summary;
 61→    if (session.slug) return session.slug;
 62→    return session.id.substring(0, 8) + "\u2026";
 63→  }
 64→
 65→  function allSessions() {
 66→    if (!dashboardData) return [];
 67→    var sessions = [];
 68→    (dashboardData.repo_groups || []).forEach(function (g) {
 69→      g.sessions.forEach(function (s) {
 70→        sessions.push({ session: s, repoName: g.repo_name || "" });
 71→      });
 72→    });
 73→    (dashboardData.non_repo_groups || []).forEach(function (g) {
 74→      var name = g.cwd.split("/").filter(Boolean).pop() || g.cwd;
 75→      g.sessions.forEach(function (s) {
 76→        sessions.push({ session: s, repoName: name });
 77→      });
 78→    });
 79→    return sessions;
 80→  }
 81→
 82→  function fuzzyMatch(text, query) {
 83→    var tLower = text.toLowerCase();
 84→    var qLower = query.toLowerCase();
 85→    var qi = 0;
 86→    var indices = [];
 87→    for (var ti = 0; ti < tLower.length && qi < qLower.length; ti++) {
 88→      if (tLower[ti] === qLower[qi]) {
 89→        indices.push(ti);
 90→        qi++;
 91→      }
 92→    }
 93→    if (qi < qLower.length) return null;
 94→    // Score: prefer consecutive matches and matches at word boundaries
 95→    var score = 0;
 96→    for (var i = 0; i < indices.length; i++) {
 97→      if (i > 0 && indices[i] === indices[i - 1] + 1) score += 10;
 98→      if (indices[i] === 0 || text[indices[i] - 1] === " ") score += 5;
 99→    }
100→    return { indices: indices, score: score };
101→  }
102→
103→  function highlightMatches(text, indices) {
104→    if (!indices || indices.length === 0) return escapeHtml(text);
105→    var result = "";
106→    var idxSet = new Set(indices);
107→    var inMark = false;
108→    for (var i = 0; i < text.length; i++) {
109→      if (idxSet.has(i) && !inMark) {
110→        result += "<mark>";
111→        inMark = true;
112→      } else if (!idxSet.has(i) && inMark) {
113→        result += "</mark>";
114→        inMark = false;
115→      }
116→      result += escapeHtml(text[i]);
117→    }
118→    if (inMark) result += "</mark>";
119→    return result;
120→  }
121→
122→  function filterSessionByTime(session) {
123→    if (timeFilterDays === Infinity) return true;
124→    if (!session.last_active) return false;
125→    var cutoff = Date.now() - timeFilterDays * 24 * 60 * 60 * 1000;
126→    return new Date(session.last_active).getTime() >= cutoff;
127→  }
128→
129→  function filterGroupSessions(group) {
130→    return group.sessions.filter(filterSessionByTime);
131→  }
132→
133→  // --- Rendering ---
134→
135→  function renderSessionRow(session) {
136→    const cssCls = statusCssClass(session.status);
137→    const row = document.createElement("div");
138→    row.className = "session-row";
139→    row.innerHTML =
140→      '<div class="status-dot ' + cssCls + '"></div>' +
141→      '<div class="session-summary">' + escapeHtml(sessionLabel(session)) + "</div>" +
142→      '<span class="status-label ' + cssCls + '">' + escapeHtml(session.status) + "</span>" +
143→      '<span class="time-ago">' + timeAgo(session.last_active) + "</span>" +
144→      '<span class="source-badge ' + session.source + '">' + session.source + "</span>";
145→
146→    row.addEventListener("click", function () {
147→      launchSession(session, row);
148→    });
149→
150→    return row;
151→  }
152→
153→  // Octocat SVG icon for git repo groups
154→  var OCTOCAT_SVG = '<svg class="octocat-icon" viewBox="0 0 16 16" width="14" height="14" fill="currentColor">' +
155→    '<path d="M8 0C3.58 0 0 3.58 0 8c0 3.54 2.29 6.53 5.47 7.59.4.07.55-.17.55-.38 0-.19-.01-.82-.01-1.49' +
156→    '-2.01.37-2.53-.49-2.69-.94-.09-.23-.48-.94-.82-1.13-.28-.15-.68-.52-.01-.53.63-.01 1.08.58 1.23.82' +
157→    '.72 1.21 1.87.87 2.33.66.07-.52.28-.87.51-1.07-1.78-.2-3.64-.89-3.64-3.95 0-.87.31-1.59.82-2.15' +
158→    '-.08-.2-.36-1.02.08-2.12 0 0 .67-.21 2.2.82.64-.18 1.32-.27 2-.27.68 0 1.36.09 2 .27 1.53-1.04 2.2-.82' +
159→    ' 2.2-.82.44 1.1.16 1.92.08 2.12.51.56.82 1.27.82 2.15 0 3.07-1.87 3.75-3.65 3.95.29.25.54.73.54 1.48' +
160→    ' 0 1.07-.01 1.93-.01 2.2 0 .21.15.46.55.38A8.013 8.013 0 0016 8c0-4.42-3.58-8-8-8z"/></svg>';
161→
162→  function buildGroupHeaderHtml(opts, isExpanded, sessionCount) {
163→    var chevron = '<span class="repo-chevron ' + (isExpanded ? "expanded" : "") + '" aria-hidden="true">\u25B6</span>';
164→    var icon = opts.icon || "";
165→    var name = '<span class="repo-name">' + escapeHtml(opts.displayName) + "</span>";
166→    var meta = '<span class="repo-meta">(' + opts.metaText + ")</span>";
167→    var btn = '<button class="btn-new-session" title="New Claude session in ' + escapeHtml(opts.cwd) + '" aria-label="New session in ' + escapeHtml(opts.displayName) + '">+</button>';
168→
169→    return (
170→      '<div class="repo-header-left">' + chevron + icon + name + meta + "</div>" +
171→      '<div class="repo-header-right">' + btn + timeAgo(opts.lastActive) + "</div>"
172→    );
173→  }
174→
175→  function renderGroup(opts, filteredSessions) {
176→    if (filteredSessions.length === 0) return null;
177→
178→    var groupKey = opts.groupKey;
179→    var isExpanded = expandedRepos.has(groupKey);
180→    var container = document.createElement("div");
181→    container.className = "repo-group";
182→
183→    var header = document.createElement("div");
184→    header.className = "repo-header";
185→    header.setAttribute("role", "button");
186→    header.setAttribute("aria-expanded", isExpanded ? "true" : "false");
187→    header.setAttribute("tabindex", "0");
188→    header.innerHTML = buildGroupHeaderHtml(opts, isExpanded, filteredSessions.length);
189→
190→    var sessionList = document.createElement("div");
191→    sessionList.className = "session-list" + (isExpanded ? "" : " collapsed");
192→
193→    // Render timeline if present
194→    if (opts.timeline && opts.timeline.length > 0) {
195→      var timelineEl = document.createElement("div");
196→      timelineEl.className = "repo-timeline";
197→      opts.timeline.forEach(function (phase) {
198→        var phaseEl = document.createElement("div");
199→        phaseEl.className = "timeline-phase";
200→        phaseEl.innerHTML =
201→          '<span class="timeline-period">' + escapeHtml(phase.period) + '</span>' +
202→          '<span class="timeline-desc">' + escapeHtml(phase.description) + '</span>';
203→        timelineEl.appendChild(phaseEl);
204→      });
205→      sessionList.appendChild(timelineEl);
206→    }
207→
208→    var showingAll = filteredSessions.length <= INITIAL_VISIBLE;
209→
210→    function renderVisibleSessions() {
211→      var timeline = sessionList.querySelector(".repo-timeline");
212→      sessionList.innerHTML = "";
213→      if (timeline) sessionList.appendChild(timeline);
214→
215→      var toShow = showingAll ? filteredSessions : filteredSessions.slice(0, INITIAL_VISIBLE);
216→      toShow.forEach(function (session) {
217→        sessionList.appendChild(renderSessionRow(session));
218→      });
219→      if (!showingAll) {
220→        var moreBtn = document.createElement("div");
221→        moreBtn.className = "show-more-btn";
222→        moreBtn.textContent = "Show all " + filteredSessions.length + " sessions";
223→        moreBtn.addEventListener("click", function (e) {
224→          e.stopPropagation();
225→          showingAll = true;
226→          renderVisibleSessions();
227→          sessionList.style.maxHeight = sessionList.scrollHeight + "px";
228→        });
229→        sessionList.appendChild(moreBtn);
230→      }
231→    }
232→    renderVisibleSessions();
233→
234→    header.querySelector(".btn-new-session").addEventListener("click", function (e) {
235→      e.stopPropagation();
236→      openNewSession(opts.cwd);
237→    });
238→
239→    header.addEventListener("click", function () {
240→      if (expandedRepos.has(groupKey)) {
241→        expandedRepos.delete(groupKey);
242→        sessionList.classList.add("collapsed");
243→        header.querySelector(".repo-chevron").classList.remove("expanded");
244→        header.setAttribute("aria-expanded", "false");
245→      } else {
246→        expandedRepos.add(groupKey);
247→        sessionList.classList.remove("collapsed");
248→        sessionList.style.maxHeight = sessionList.scrollHeight + "px";
249→        header.querySelector(".repo-chevron").classList.add("expanded");
250→        header.setAttribute("aria-expanded", "true");
251→      }
252→    });
253→
254→    if (isExpanded) {
255→      requestAnimationFrame(function () {
256→        sessionList.style.maxHeight = sessionList.scrollHeight + "px";
257→      });
258→    }
259→
260→    container.appendChild(header);
261→    container.appendChild(sessionList);
262→    return container;
263→  }
264→
265→  function renderRepoGroup(group, filteredSessions) {
266→    var metaParts = [];
267→    if (group.git_branch) metaParts.push(group.git_branch);
268→    if (group.git_dirty) metaParts.push('<span class="dirty">dirty</span>');
269→    if (group.unpushed_commits > 0) metaParts.push('<span class="unpushed">' + group.unpushed_commits + " unpushed</span>");
270→    if (!group.git_dirty && group.unpushed_commits === 0) metaParts.push("clean");
271→    metaParts.push(filteredSessions.length + " sessions");
272→
273→    return renderGroup({
274→      groupKey: group.repo_root,
275→      displayName: group.repo_name,
276→      icon: OCTOCAT_SVG,
277→      metaText: metaParts.join(", "),
278→      cwd: group.repo_root,
279→      lastActive: group.last_active,
280→      timeline: group.timeline,
281→    }, filteredSessions);
282→  }
283→
284→  function renderNonRepoGroup(group, filteredSessions) {
285→    var displayName = group.cwd.split("/").filter(Boolean).pop() || group.cwd;
286→
287→    return renderGroup({
288→      groupKey: group.cwd,
289→      displayName: displayName,
290→      icon: "",
291→      metaText: filteredSessions.length + " sessions",
292→      cwd: group.cwd,
293→      lastActive: group.last_active,
294→      timeline: group.timeline,
295→    }, filteredSessions);
296→  }
297→
298→  function render() {
299→    if (!dashboardData) return;
300→
301→    $loading.classList.add("hidden");
302→
303→    var hasRepos = (dashboardData.repo_groups || []).length > 0;
304→    var hasNonRepos = (dashboardData.non_repo_groups || []).length > 0;
305→
306→    if (!hasRepos && !hasNonRepos) {
307→      $emptyState.classList.remove("hidden");
308→      $repoGroups.classList.add("hidden");
309→      $nonRepoGroups.classList.add("hidden");
310→      $chronoView.classList.add("hidden");
311→      return;
312→    }
313→
314→    $emptyState.classList.add("hidden");
315→    $chronoView.classList.add("hidden");
316→    $repoGroups.classList.remove("hidden");
317→    $nonRepoGroups.classList.add("hidden");
318→
319→    // Combine repo and non-repo groups into one list sorted by last_active
320→    var allGroups = [];
321→    (dashboardData.repo_groups || []).forEach(function (g) {
322→      allGroups.push({ type: "repo", group: g, last_active: g.last_active });
323→    });
324→    (dashboardData.non_repo_groups || []).forEach(function (g) {
325→      allGroups.push({ type: "non-repo", group: g, last_active: g.last_active });
326→    });
327→    allGroups.sort(function (a, b) {
328→      return new Date(b.last_active) - new Date(a.last_active);
329→    });
330→
331→    // Auto-expand the first group on initial render
332→    if (expandedRepos.size === 0 && allGroups.length > 0) {
333→      var firstGroup = allGroups[0];
334→      var expandKey = firstGroup.type === "repo" ? firstGroup.group.repo_root : firstGroup.group.cwd;
335→      expandedRepos.add(expandKey);
336→    }
337→
338→    $repoGroups.innerHTML = "";
339→    allGroups.forEach(function (entry) {
340→      var filtered = filterGroupSessions(entry.group);
341→      var el = entry.type === "repo"
342→        ? renderRepoGroup(entry.group, filtered)
343→        : renderNonRepoGroup(entry.group, filtered);
344→      if (el) $repoGroups.appendChild(el);
345→    });
346→  }
347→
348→  // --- API ---
349→
350→  function fetchSessions() {
351→    return fetch("/api/sessions")
352→      .then(function (res) { return res.json(); })
353→      .then(function (data) {
354→        dashboardData = data;
355→        lastScannedTime = data.last_scanned;
356→        updateSliderRange();
357→        render();
358→        updateLastScan();
359→      })
360→      .catch(function (err) {
361→        console.error("Failed to fetch sessions:", err);
362→      });
363→  }
364→
365→  function refreshSessions() {
366→    var days = parseInt($scanDays.value, 10) || 7;
367→    $btnRefresh.classList.add("spinning");
368→    $btnRefresh.textContent = "Refreshing...";
369→    return fetch("/api/refresh?scan_days=" + days)
370→      .then(function (res) { return res.json(); })
371→      .then(function (data) {
372→        dashboardData = data;
373→        lastScannedTime = data.last_scanned;
374→        updateSliderRange();
375→        render();
376→        updateLastScan();
377→      })
378→      .catch(function (err) {
379→        console.error("Failed to refresh:", err);
380→      })
381→      .finally(function () {
382→        $btnRefresh.classList.remove("spinning");
383→        $btnRefresh.textContent = "Refresh";
384→      });
385→  }
386→
387→  function launchSession(session, rowEl) {
388→    rowEl.classList.add("launched");
389→    setTimeout(function () { rowEl.classList.remove("launched"); }, 500);
390→    openTerminal(session);
391→  }
392→
393→  // --- Terminal Tabs ---
394→
395→  var terminals = {};       // tabId → tabData
396→  var activeTabId = null;
397→  var tabIdCounter = 0;
398→  var resizeListenerAttached = false;
399→
400→  var $terminalPanel = document.getElementById("terminal-panel");
401→  var $terminalContainer = document.getElementById("terminal-container");
402→  var $terminalTabs = document.getElementById("terminal-tabs");
403→  var $terminalClose = document.getElementById("terminal-close");
404→
405→  function generateTabId() {
406→    return "tab-" + (tabIdCounter++);
407→  }
408→
409→  function renderTabs() {
410→    $terminalTabs.innerHTML = "";
411→    var ids = Object.keys(terminals);
412→    ids.forEach(function (tabId) {
413→      var tab = terminals[tabId];
414→      var el = document.createElement("div");
415→      el.className = "terminal-tab" + (tabId === activeTabId ? " active" : "") + (tab.ended ? " ended" : "");
416→      el.innerHTML =
417→        '<span class="terminal-tab-title">' + escapeHtml(tab.title) + '</span>' +
418→        '<span class="terminal-tab-close">&times;</span>';
419→
420→      el.querySelector(".terminal-tab-title").addEventListener("click", function () {
421→        switchTab(tabId);
422→      });
423→      el.querySelector(".terminal-tab-close").addEventListener("click", function (e) {
424→        e.stopPropagation();
425→        closeTab(tabId);
426→      });
427→
428→      $terminalTabs.appendChild(el);
429→    });
430→  }
431→
432→  function switchTab(tabId) {
433→    if (!terminals[tabId]) return;
434→    if (activeTabId && terminals[activeTabId]) {
435→      terminals[activeTabId].container.classList.remove("active");
436→    }
437→    activeTabId = tabId;
438→    terminals[tabId].container.classList.add("active");
439→    terminals[tabId].fitAddon.fit();
440→    terminals[tabId].term.focus();
441→    renderTabs();
442→  }
443→
444→  function closeTab(tabId) {
445→    var tab = terminals[tabId];
446→    if (!tab) return;
447→    tab.ws.close();
448→    tab.term.dispose();
449→    tab.container.remove();
450→    delete terminals[tabId];
451→
452→    if (activeTabId === tabId) {
453→      var remaining = Object.keys(terminals);
454→      if (remaining.length > 0) {
455→        switchTab(remaining[remaining.length - 1]);
456→      } else {
457→        activeTabId = null;
458→        $terminalPanel.classList.add("hidden");
459→        document.body.classList.remove("terminal-open");
460→        window.removeEventListener("resize", handleTerminalResize);
461→        resizeListenerAttached = false;
462→      }
463→    }
464→    renderTabs();
465→  }
466→
467→  function createTerminalTab(title, wsParams, sessionId) {
468→    var tabId = generateTabId();
469→
470→    var container = document.createElement("div");
471→    container.className = "terminal-tab-container";
472→    $terminalContainer.appendChild(container);
473→
474→    var term = new Terminal({
475→      fontFamily: '"JetBrains Mono", "SF Mono", monospace',
476→      fontSize: 13,
477→      theme: {
478→        background: "#111111",
479→        foreground: "#FAFAFA",
480→        cursor: "#FF4D00",
481→      },
482→      cursorBlink: true,
483→    });
484→
485→    var fitAddon = new FitAddon.FitAddon();
486→    term.loadAddon(fitAddon);
487→    term.loadAddon(new WebLinksAddon.WebLinksAddon());
488→
489→    term.open(container);
490→
491→    var tabData = {
492→      id: tabId,
493→      term: term,
494→      ws: null,
495→      fitAddon: fitAddon,
496→      container: container,
497→      title: title,
498→      ended: false,
499→      sessionId: sessionId,
500→    };
501→    terminals[tabId] = tabData;
502→
503→    $terminalPanel.classList.remove("hidden");
504→    document.body.classList.add("terminal-open");
505→
506→    // Hide previous active tab, show this one
507→    if (activeTabId && terminals[activeTabId]) {
508→      terminals[activeTabId].container.classList.remove("active");
509→    }
510→    activeTabId = tabId;
511→    container.classList.add("active");
512→    fitAddon.fit();
513→
514→    var params = new URLSearchParams(wsParams);
515→    var wsProtocol = location.protocol === "https:" ? "wss:" : "ws:";
516→    var wsUrl = wsProtocol + "//" + location.host + "/ws/terminal?" + params.toString();
517→    var ws = new WebSocket(wsUrl);
518→    tabData.ws = ws;
519→
520→    ws.onopen = function () {
521→      ws.send(JSON.stringify({ type: "resize", cols: term.cols, rows: term.rows }));
522→      term.focus();
523→    };
524→
525→    ws.onmessage = function (evt) {
526→      term.write(evt.data);
527→    };
528→
529→    ws.onclose = function () {
530→      term.write("\r\n\x1b[90m[session ended]\x1b[0m\r\n");
531→      tabData.ended = true;
532→      renderTabs();
533→    };
534→
535→    term.onData(function (data) {
536→      if (ws.readyState === WebSocket.OPEN) ws.send(data);
537→    });
538→
539→    term.onResize(function (size) {
540→      if (ws.readyState === WebSocket.OPEN) {
541→        ws.send(JSON.stringify({ type: "resize", cols: size.cols, rows: size.rows }));
542→      }
543→    });
544→
545→    if (!resizeListenerAttached) {
546→      window.addEventListener("resize", handleTerminalResize);
547→      resizeListenerAttached = true;
548→    }
549→
550→    renderTabs();
551→    return tabId;
552→  }
553→
554→  function openTerminal(session) {
555→    // If this session already has a tab, switch to it
556→    var ids = Object.keys(terminals);
557→    for (var i = 0; i < ids.length; i++) {
558→      if (terminals[ids[i]].sessionId === session.id) {
559→        switchTab(ids[i]);
560→        return;
561→      }
562→    }
563→    createTerminalTab(sessionLabel(session), {
564→      source: session.source,
565→      session_id: session.id,
566→      cwd: session.cwd,
567→    }, session.id);
568→  }
569→
570→  function openNewSession(cwd) {
571→    var displayName = cwd.split("/").filter(Boolean).pop() || cwd;
572→    createTerminalTab("New: " + displayName, { mode: "new", cwd: cwd }, null);
573→  }
574→
575→  function handleTerminalResize() {
576→    if (activeTabId && terminals[activeTabId]) {
577→      terminals[activeTabId].fitAddon.fit();
578→    }
579→  }
580→
581→  $terminalClose.addEventListener("click", function () {
582→    if (activeTabId) closeTab(activeTabId);
583→  });
584→
585→  // --- Last scan timer ---
586→
587→  function updateLastScan() {
588→    if (lastScannedTime) {
589→      $lastScan.textContent = "Last scan: " + timeAgo(lastScannedTime);
590→    }
591→  }
592→
593→  // --- Time Slider ---
594→
595→  function computeMaxDays() {
596→    if (!dashboardData) return 60;
597→    var oldest = Infinity;
598→    var all = allSessions();
599→    all.forEach(function (entry) {
600→      if (entry.session.last_active) {
601→        var t = new Date(entry.session.last_active).getTime();
602→        if (t < oldest) oldest = t;
603→      }
604→    });
605→    if (oldest === Infinity) return 60;
606→    return Math.max(1, Math.ceil((Date.now() - oldest) / (24 * 60 * 60 * 1000)));
607→  }
608→
609→  function updateSliderRange() {
610→    var maxDays = computeMaxDays();
611→    $timeSlider.max = maxDays;
612→    $timeSlider.value = maxDays;
613→    timeFilterDays = Infinity;
614→    updateSliderLabel(maxDays, maxDays);
615→  }
