617→  function updateSliderLabel(val, max) {
618→    if (val >= max) {
619→      $timeSliderLabel.textContent = "All time";
620→    } else if (val === 1) {
621→      $timeSliderLabel.textContent = "Last 24h";
622→    } else {
623→      $timeSliderLabel.textContent = "Last " + val + "d";
624→    }
