628→    var val = parseInt($timeSlider.value, 10);
629→    var max = parseInt($timeSlider.max, 10);
630→    if (val >= max) {
631→      timeFilterDays = Infinity;
632→    } else {
633→      timeFilterDays = val;
634→    }
635→    updateSliderLabel(val, max);
636→    render();
