639→  // --- Search Overlay ---
640→
641→  var searchSelectedIdx = 0;
642→  var searchMatches = [];
643→  var previouslyFocusedElement = null;
644→
645→  function openSearch() {
646→    previouslyFocusedElement = document.activeElement;
647→    $searchOverlay.classList.remove("hidden");
648→    $searchInput.value = "";
649→    $searchResults.innerHTML = "";
650→    searchSelectedIdx = 0;
651→    searchMatches = [];
652→    $searchInput.focus();
653→  }
654→
655→  function closeSearch() {
656→    $searchOverlay.classList.add("hidden");
657→    $searchInput.value = "";
658→    $searchResults.innerHTML = "";
659→    if (previouslyFocusedElement && previouslyFocusedElement.focus) {
660→      previouslyFocusedElement.focus();
661→    }
662→    previouslyFocusedElement = null;
663→  }
664→
665→  function performSearch(query) {
666→    $searchResults.innerHTML = "";
667→    searchSelectedIdx = 0;
668→
669→    if (!query.trim()) {
670→      searchMatches = [];
671→      return;
672→    }
673→
674→    var all = allSessions();
675→    var scored = [];
676→    all.forEach(function (entry) {
677→      var label = sessionLabel(entry.session);
678→      var searchText = label + " " + entry.repoName + " " + (entry.session.status || "");
679→      var m = fuzzyMatch(searchText, query);
680→      if (m) {
681→        // Re-match just the label for highlighting
682→        var labelMatch = fuzzyMatch(label, query);
683→        scored.push({
684→          session: entry.session,
685→          repoName: entry.repoName,
686→          score: m.score,
687→          labelIndices: labelMatch ? labelMatch.indices : [],
688→        });
689→      }
690→    });
691→
692→    scored.sort(function (a, b) { return b.score - a.score; });
693→    searchMatches = scored.slice(0, 50);
694→
695→    if (searchMatches.length === 0) {
696→      $searchResults.innerHTML = '<div class="search-no-results">No matches</div>';
697→      return;
698→    }
699→
700→    searchMatches.forEach(function (match, idx) {
701→      var row = document.createElement("div");
702→      row.className = "search-result-row" + (idx === 0 ? " selected" : "");
703→      var cssCls = statusCssClass(match.session.status);
704→      row.innerHTML =
705→        '<div class="status-dot ' + cssCls + '"></div>' +
706→        '<div>' +
707→          '<div class="search-result-summary">' +
708→            highlightMatches(sessionLabel(match.session), match.labelIndices) +
709→          '</div>' +
710→          '<span class="search-result-repo">' + escapeHtml(match.repoName) + '</span>' +
711→        '</div>' +
712→        '<span class="status-label ' + cssCls + '">' +
713→          escapeHtml(match.session.status) + '</span>' +
714→        '<span class="time-ago">' + timeAgo(match.session.last_active) + '</span>';
715→
716→      row.addEventListener("click", function () {
717→        closeSearch();
718→        launchFromSearch(match.session);
719→      });
720→      $searchResults.appendChild(row);
721→    });
722→  }
723→
724→  function launchFromSearch(session) {
725→    openTerminal(session);
726→  }
727→
728→  function updateSearchSelection() {
729→    var rows = $searchResults.querySelectorAll(".search-result-row");
730→    rows.forEach(function (r, i) {
731→      r.classList.toggle("selected", i === searchSelectedIdx);
732→    });
733→    if (rows[searchSelectedIdx]) {
734→      rows[searchSelectedIdx].scrollIntoView({ block: "nearest" });
735→    }
736→  }
737→
738→  $searchInput.addEventListener("input", function () {
739→    performSearch($searchInput.value);
740→  });
741→
742→  $searchInput.addEventListener("keydown", function (e) {
743→    if (e.key === "Escape") {
744→      e.preventDefault();
745→      closeSearch();
746→    } else if (e.key === "ArrowDown") {
747→      e.preventDefault();
748→      if (searchMatches.length > 0) {
749→        searchSelectedIdx = Math.min(searchSelectedIdx + 1, searchMatches.length - 1);
750→        updateSearchSelection();
751→      }
752→    } else if (e.key === "ArrowUp") {
753→      e.preventDefault();
754→      if (searchMatches.length > 0) {
755→        searchSelectedIdx = Math.max(searchSelectedIdx - 1, 0);
756→        updateSearchSelection();
757→      }
758→    } else if (e.key === "Enter") {
759→      e.preventDefault();
760→      if (searchMatches.length > 0 && searchMatches[searchSelectedIdx]) {
761→        closeSearch();
762→        launchFromSearch(searchMatches[searchSelectedIdx].session);
763→      }
764→    }
765→  });
766→
767→  $searchOverlay.addEventListener("click", function (e) {
768→    if (e.target === $searchOverlay) closeSearch();
769→  });
