771→  // --- Keyboard Help Overlay ---
772→
773→  var $helpOverlay = document.getElementById("help-overlay");
774→
775→  function openHelp() {
776→    $helpOverlay.classList.remove("hidden");
777→  }
778→
779→  function closeHelp() {
780→    $helpOverlay.classList.add("hidden");
781→  }
782→
