784→    if (e.target === $helpOverlay) closeHelp();
785→  });
786→
787→  // --- Group Navigation (j/k) ---
788→
789→  var focusedGroupIdx = -1;
790→
791→  function getAllGroupElements() {
792→    return Array.from($repoGroups.querySelectorAll(".repo-group"));
793→  }
794→
795→  function setGroupFocus(idx) {
796→    var groups = getAllGroupElements();
797→    // Clear previous focus
798→    groups.forEach(function (el) {
799→      el.classList.remove("group-focused");
800→    });
801→    if (idx < 0 || idx >= groups.length) {
802→      focusedGroupIdx = -1;
803→      return;
804→    }
805→    focusedGroupIdx = idx;
806→    groups[idx].classList.add("group-focused");
807→    groups[idx].scrollIntoView({ block: "nearest", behavior: "smooth" });
808→  }
809→
810→  function toggleFocusedGroup() {
811→    var groups = getAllGroupElements();
812→    if (focusedGroupIdx < 0 || focusedGroupIdx >= groups.length) return;
813→    var header = groups[focusedGroupIdx].querySelector(".repo-header");
814→    if (header) header.click();
815→  }
816→
817→  // --- Global Keyboard Handler ---
818→
819→  document.addEventListener("keydown", function (e) {
820→    // Don't trigger if typing in an input or textarea
821→    if (e.target.tagName === "INPUT" || e.target.tagName === "TEXTAREA") return;
822→
823→    // Help overlay takes priority for close
824→    if (!$helpOverlay.classList.contains("hidden")) {
825→      if (e.key === "Escape" || e.key === "?") {
826→        e.preventDefault();
827→        closeHelp();
828→      }
829→      return;
830→    }
831→
832→    // Escape closes active terminal tab (returns focus to dashboard)
833→    if (e.key === "Escape" && activeTabId) {
834→      e.preventDefault();
835→      closeTab(activeTabId);
836→      return;
837→    }
838→
839→    // When terminal is focused, only Escape works (handled above)
840→    if (activeTabId) return;
841→
842→    if (e.key === "/") {
843→      e.preventDefault();
844→      openSearch();
845→    } else if (e.key === "?") {
846→      e.preventDefault();
847→      openHelp();
848→    } else if (e.key === "r") {
849→      e.preventDefault();
850→      refreshSessions();
851→    } else if (e.key === "j") {
852→      e.preventDefault();
853→      var groups = getAllGroupElements();
854→      if (groups.length > 0) {
855→        setGroupFocus(Math.min(focusedGroupIdx + 1, groups.length - 1));
856→      }
857→    } else if (e.key === "k") {
858→      e.preventDefault();
859→      if (focusedGroupIdx > 0) {
860→        setGroupFocus(focusedGroupIdx - 1);
861→      }
862→    } else if (e.key === "Enter" && focusedGroupIdx >= 0) {
863→      e.preventDefault();
864→      toggleFocusedGroup();
865→    }
866→  });
867→
868→  // --- Event listeners ---
869→
870→  $btnRefresh.addEventListener("click", refreshSessions);
871→
872→  // --- Init ---
873→
874→  fetchSessions();
875→})();
