578→<script>
579→  const slides = document.querySelectorAll('.slide');
580→  const dots = document.querySelectorAll('.nav-dots a');
581→  const inners = document.querySelectorAll('.slide-inner');
582→
583→  const observer = new IntersectionObserver((entries) => {
584→    entries.forEach(entry => {
585→      if (entry.isIntersecting) {
586→        entry.target.querySelector('.slide-inner').classList.add('visible');
587→        const idx = Array.from(slides).indexOf(entry.target);
588→        dots.forEach((d, i) => d.classList.toggle('active', i === idx));
589→      }
590→    });
591→  }, { threshold: 0.35 });
592→
593→  slides.forEach(s => observer.observe(s));
594→</script>
